268	/// Run a tabtarget and check exit 0.
269	fn rbtdrf_run_tt(
270	    project_root: &Path,
271	    colophon: &str,
272	    args: &[&str],
273	    dir: &Path,
274	    label: &str,
275	) -> Result<(), String> {
276	    let tt = rbtdri_find_tabtarget_global(project_root, colophon)?;
277	    let output = rbtdri_tabtarget_command(&tt)
278	        .args(args)
279	        .current_dir(project_root)
280	        .output()
281	        .map_err(|e| format!("{}: failed to run {}: {}", label, tt.display(), e))?;
282	
283	    let code = output.status.code().unwrap_or(-1);
284	    let _ = std::fs::write(dir.join(format!("{}-stdout.txt", label)), &output.stdout);
285	    let _ = std::fs::write(dir.join(format!("{}-stderr.txt", label)), &output.stderr);
286	
287	    if code != 0 {
288	        return Err(format!(
289	            "{}: {} exited {} — {}",
290	            label,
291	            colophon,
292	            code,
293	            String::from_utf8_lossy(&output.stderr),
294	        ));
295	    }
296	    Ok(())
297	}
