// ── Helpers ──────────────────────────────────────────────────

/// Sub-assertion within a case: run bash snippet, check exit code.
struct RbtdrfSub {
    label: &'static str,
    setup: &'static str,
    command: &'static str,
    expect_ok: bool,
}

impl RbtdrfSub {
