    let _ = std::fs::write(dir.join(format!("{}-stdout.txt", trace_prefix)), &stdout);
    let _ = std::fs::write(dir.join(format!("{}-stderr.txt", trace_prefix)), &stderr);

    Ok((code, stdout, stderr))
