// ── Regime-poison cases ─────────────────────────────────────
//
// In-universe negatives: drive the REAL validate verb against a real regime
// with one field corrupted via the regime-poison tweak (zbuv_poison_apply, the
// one BUK regime-load membrane), and assert the SPECIFIC band code of the gate
// that fires — RBTDGC_BAND_REGIME (100) when a regime module's own enforce rule
// rejects (cross-field, format regex, existence), RBTDGC_BAND_ENROLL (101) when
// the buv enrollment pipeline rejects (buv_vet type/format/enum/range/presence,
// or buv_scope_sentinel on an unexpected variable). The poison rides
// BURE_TWEAK_NAME + BURE_TWEAK_VALUE as extra env on the validate Command; this
// fixture is not credless, so the tweak slot is free (no conflict gate).
// Asserting the band — not bare nonzero — closes the wrong-layer hole: a harness
// breakage exits with some other code and fails the case loud.

/// Drive a validate tabtarget under the regime-poison tweak, asserting the exit
/// equals `expected_band`. `folio` is the verb's positional args (empty for
/// repo/depot/payor; the nameplate/vessel moniker otherwise). `poison` is the
/// BURE_TWEAK_VALUE: "VAR=value" to corrupt a field, bare "VAR" to unset a
/// required one. The corrupted VAR must carry the regime's enroll scope prefix
/// or the seam rides inert (zbuv_poison_apply scope guard).
fn rbtdrf_rp_poison(
    dir: &Path,
    validate_colophon: &str,
    folio: &[&str],
    poison: &str,
    expected_band: i32,
    label: &str,
) -> rbtdre_Verdict {
    let root = match std::env::current_dir() {
        Ok(r) => r,
        Err(e) => return rbtdre_Verdict::Fail(format!("cannot get cwd: {}", e)),
    };
    let tt = match rbtdri_find_tabtarget_global(&root, validate_colophon) {
        Ok(p) => p,
        Err(e) => return rbtdre_Verdict::Fail(e),
    };
    let output = match rbtdri_tabtarget_command(&tt)
        .args(folio)
        .env(RBTDRI_BURE_TWEAK_NAME_KEY, RBTDGC_TWEAK_REGIME_POISON)
        .env(RBTDRI_BURE_TWEAK_VALUE_KEY, poison)
        .current_dir(&root)
